// ── Blitz utilities ─────────────────────────────────────────────────────────

export function getBlitzPool(tag: string): GameEntry[] {
  return GAMES_DB.filter(g => g.tags.includes(tag))
}

export function getBlitzPoolSize(tag: string): number {
  return getBlitzPool(tag).length
}
